1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const key = (x: number, y: number): string => `${x},${y}`;
10	const parseKey = (k: string): Cell => {
11	  const [xs, ys] = k.split(",");
12	  return [Number(xs), Number(ys)];
13	};
14	
15	export const nextGeneration = (cells: Cell[]): Cell[] => {
16	  const alive = new Set(cells.map(([x, y]) => key(x, y)));
17	  const neighborCounts = new Map<string, number>();
18	
19	  for (const [x, y] of cells) {
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const k = key(x + dx, y + dy);
22	      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
23	    }
24	  }
25	
26	  const survives = (k: string, count: number): boolean =>
27	    count === 3 || (count === 2 && alive.has(k));
28	
29	  const result: Cell[] = [];
30	  for (const [k, count] of neighborCounts) {
31	    if (survives(k, count)) result.push(parseKey(k));
32	  }
33	  return result;
34	};
35

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return an empty array when given no cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block unchanged (each cell has 3 neighbors)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
19	      new Set(block.map(([x, y]) => `${x},${y}`))
20	    );
21	  });
22	  it("should rotate a vertical blinker into a horizontal blinker", () => {
23	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
24	    const result = nextGeneration(vertical);
25	    expect(result).toHaveLength(3);
26	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
27	      new Set(["-1,1", "0,1", "1,1"])
28	    );
29	  });
30	  it("should kill an overpopulated cell (more than 3 neighbors)", () => {
31	    // Center (1,1) has 4 live neighbors → dies
32	    const input: [number, number][] = [
33	      [0, 0], [1, 0], [2, 0],
34	      [1, 1],
35	      [0, 2],         [2, 2],
36	    ];
37	    const result = nextGeneration(input);
38	    const resultKeys = new Set(result.map(([x, y]) => `${x},${y}`));
39	    expect(resultKeys.has("1,1")).toBe(false);
40	  });
41	  it("should bring a dead cell to life with exactly 3 neighbors (reproduction)", () => {
42	    // Dead cell (1,1) has exactly 3 live neighbors → becomes alive
43	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
44	    const result = nextGeneration(input);
45	    const resultKeys = new Set(result.map(([x, y]) => `${x},${y}`));
46	    expect(resultKeys.has("1,1")).toBe(true);
47	  });
48	  it("should handle negative coordinates correctly", () => {
49	    // Vertical blinker at x=-5: cells (-5,-1),(-5,0),(-5,1)
50	    // Should rotate to horizontal: (-6,0),(-5,0),(-4,0)
51	    const vertical: [number, number][] = [[-5, -1], [-5, 0], [-5, 1]];
52	    const result = nextGeneration(vertical);
53	    expect(result).toHaveLength(3);
54	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
55	      new Set(["-6,0", "-5,0", "-4,0"])
56	    );
57	  });
58	});
